
public class Operadores {

    public static void main(String[] args) {
        // TODO Auto-generated method stub

        // Suma
        int num1 = 46;
        int num2 = 65;
        float suma = num1 + num2;
        System.out.println("La suma de " + num1 + " y " + num2 + " es " + suma);

        // Resta
        int num3 = 80;
        int num4 = 7;
        float resta = num3 - num4;
        System.out.println("La resta de " + num3 + " y " + num4 + " es " + resta);

        // Multiplicación
        int num5 = 80;
        int num6 = 7;
        float multi = num5 * num6;
        System.out.println("La multiplicacion de " + num5 + " y " + num6 + " es " + multi);

        // División
        int num7 = 80;
        int num8 = 7;
        float divi = num7 / num8;
        System.out.println("La division de " + num7 + " y " + num8 + " es " + divi);

        // Módulo
        int num9 = 80;
        int num10 = 7;
        float mod = num9 % num10;
        System.out.println("La Modulo de " + num9 + " y " + num10 + " es " + mod);
    }
}